module RefModule (
    input clk,
    input resetn,
    input j,
    input k,
    output reg q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge resetn or posedge dbg_halt) begin
    if (~resetn)
        q <= 0;
    else if (j & ~k)
        q <= 1;
    else if (~j & k)
        q <= 0;
    else if (j & k)
        q <= ~q;
end
endmodule
